<template>
    <div id="box">
        <Header title="登录" v-if="!ifWx" />
        <div class="mainBox">
            <SubHeader subTitle="欢迎来到诺信学院" />
            <van-form class="main" validate-first  >
                <van-field
                        v-model="state.cellphone"
                        type="tel"
                        label=""
                        clearable
                        placeholder="请输入手机号"
                        :rules="[
                        { required: true, message: '请填写验证码' },
                        { pattern: /^1[3456789]\d{9}$/, message: '手机号格式不正确' }
                    ]"

                />
                <van-field
                        v-model="state.code"
                        center
                        type="digit"
                        clearable
                        label=""
                        placeholder="请输入验证码"
                        :rules="[{ required: true, message: '获取验证码' }]"
                >
                    <template #button>
                        <van-button size="small" type="primary" @click="sendCode" :disabled="state.cellphone.replace(/(^\s*)|(\s*$)/ig, '').length !== 11"> {{state.codeText}}</van-button>
                    </template>
                </van-field>
                <div class="subBtnBox">
                    <van-button  block type="primary"  @click="onSubmit" >登录</van-button>
                </div>
            </van-form>
        </div>
        <Footer/>
    </div>
</template>
<script>
import Header from '@/components/Header'
import Footer from '@/components/Footer'
import SubHeader from '@/components/SubHeader'
import { reactive } from 'vue'
import { useRouter } from 'vue-router'
import useIfWx from '../../mixin/useIfWx'
export default {
    setup() {
        const { ifWx } = useIfWx()
        const state = reactive({
            cellphone: '',
            code: '',
            codeText: '发送验证码'
        })
        const router = useRouter()
        const onSubmit = (values) => {
            console.log('submit', values)
            console.log('submit', router)
            router.push({
                name: 'question_checkpwd'
            })
        }
        const sendCode = () => {
            if (!state.timer) {
                let { cellphone } = state
                cellphone = cellphone.toString()
                if (!cellphone) {
                    console.log('手机号不能为空')
                    return
                }
                cellphone = cellphone.replace(/(^\s*)|(\s*$)/ig, '')
                if (!/^1[3456789]\d{9}$/.test(cellphone)) {
                    console.log('手机号格式不正确')
                    return
                }
                // 可以发送验证码
                var count = 6
                state.timer = setInterval(() => {
                    count--
                    state.codeText = count
                    if (count <= 0) {
                        clearInterval(state.timer)
                        state.timer = null
                        state.codeText = '发送验证码'
                    }
                }, 1000)
                // this.Ajax.post(this.apiUrl.sendCode,{
                //     cellphone,
                // }).then(res=>{
                //     this.$message.success('验证码发送成功');
                // })
            }
        }
        return {
            ifWx,
            state,
            onSubmit,
            sendCode
        }
    },
    components: {
        Header, Footer, SubHeader
    }
}
</script>

<style lang="less">
    .subBtnBox{
        margin-top: 70px;
    }
    .van-cell{
        padding-left: 0;
        padding-right: 0;
    }
</style>

